commands_run.command:
node - <<'NODE'
const fs = require('fs');
const path = 'evals/effectiveness/datasets/m12-mini.jsonl';
const rows = fs.readFileSync(path, 'utf8').trimEnd().split(/\n/).map((line) => JSON.parse(line));
for (const row of rows) {
  if (row.case_id === 'feature-small-002') {
    row.baseline_prompt = 'Implement slug normalization for project routes in src/project-slug.js. Keep changes scoped and run npm test.';
    row.treatment_goal = 'Use Codex Loop SDK-Orchestrated Mode to plan, implement, evaluate, repair if needed, and report slug normalization in project routes.';
    row.expected_artifacts = ['artifacts/FinalDeliveryReport.md'];
    row.baseline_expected_artifacts = [];
    row.treatment_expected_artifacts = [
      'docs/PRD.md',
      'docs/TASK_GRAPH.json',
      'artifacts/dev-result.json',
      'artifacts/eval-report.json',
      'artifacts/FinalDeliveryReport.md',
      'artifacts/repair-request.json',
      'artifacts/repair-result.json',
      'artifacts/final-eval-report.json'
    ];
    row.forbidden_files = ['.env', 'database.sqlite', 'package.json', 'package-lock.json', 'README.md'];
  }
}
fs.writeFileSync(path, rows.map((row) => JSON.stringify(row)).join('\n') + '\n');
NODE
